namespace sv_adebc468969c496589f5fe7a6330b0f0.Models;

// Immutable records for submission
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable models for form editing
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
}

using sv_adebc468969c496589f5fe7a6330b0f0.Models;

namespace sv_adebc468969c496589f5fe7a6330b0f0.Services;

public class ApplicationService : IApplicationService
{
    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        await Task.Delay(1000);
        return Random.Shared.Next(10000, 99999);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(300);
        return !string.IsNullOrWhiteSpace(email)
            && email.Contains('@')
            && email.Contains('.');
    }
}

@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<nav class="step-indicator mb-4" aria-label="Application progress">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i + 1;
        var isCompleted = CompletedSteps.Contains(step);
        var isCurrent = step == CurrentStep;

        @if (i > 0)
        {
            <div class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")"></div>
        }

        <div class="step @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(step > CurrentStep && !isCompleted ? "future" : "")"
             role="listitem"
             @onclick="() => HandleStepClick(step)"
             @onclick:preventDefault>
            <div class="step-circle">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <div class="step-label">@StepNames[i]</div>
        </div>
    }
</nav>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = new();

    [Parameter, EditorRequired]
    public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="Enter your full name" />
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" placeholder="you@example.com" />
    @if (IsValidatingEmail)
    {
        <div class="form-text text-info">Validating email...</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control" rows="2" @bind="Model.Address" @bind:event="oninput" placeholder="Street address, city, state, zip"></textarea>
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidatingEmail">
        Next &raquo;
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private List<string> Errors { get; set; } = new();
    private bool IsValidatingEmail { get; set; }

    private async Task HandleNext()
    {
        Errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName))
            Errors.Add("Full name is required.");
        if (string.IsNullOrWhiteSpace(Model.Email))
            Errors.Add("Email is required.");
        if (string.IsNullOrWhiteSpace(Model.Phone))
            Errors.Add("Phone is required.");
        if (string.IsNullOrWhiteSpace(Model.Address))
            Errors.Add("Address is required.");

        if (Errors.Count > 0) return;

        IsValidatingEmail = true;
        StateHasChanged();

        var isValidEmail = await ValidateEmail(Model.Email);
        IsValidatingEmail = false;

        if (!isValidEmail)
        {
            Errors.Add("Please enter a valid email address.");
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryEditor Model="Entries[index]"
                     Index="index + 1"
                     CanRemove="Entries.Count > 1"
                     OnRemove="() => RemoveEntry(index)" />
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
</div>

@code {
    [Parameter, EditorRequired]
    public List<WorkEntryModel> Entries { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private List<string> Errors { get; set; } = new();

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var entry = Entries[i];
            if (string.IsNullOrWhiteSpace(entry.Company))
                Errors.Add($"Position {i + 1}: Company is required.");
            if (string.IsNullOrWhiteSpace(entry.Title))
                Errors.Add($"Position {i + 1}: Job title is required.");
            if (entry.StartDate is null)
                Errors.Add($"Position {i + 1}: Start date is required.");
        }

        if (Errors.Count > 0) return;

        await OnNext.InvokeAsync();
    }
}

@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">References</h4>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceEditor Model="References[index]"
                     Index="index + 1"
                     CanRemove="References.Count > 2"
                     OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
</div>

@code {
    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private List<string> Errors { get; set; } = new();

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            if (string.IsNullOrWhiteSpace(r.Name))
                Errors.Add($"Reference {i + 1}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship))
                Errors.Add($"Reference {i + 1}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email))
                Errors.Add($"Reference {i + 1}: Email is required.");
        }

        if (Errors.Count > 0) return;

        await OnNext.InvokeAsync();
    }
}

@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="CoverLetter" @bind:event="oninput"
              @bind:after="NotifyChanged"
              placeholder="Write your cover letter here..."></textarea>
    <div class="form-text text-end">
        @CoverLetter.Length / @MaxCharacters characters
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next &raquo;</button>
</div>

@code {
    private const int MaxCharacters = 2000;

    [Parameter, EditorRequired]
    public string CoverLetter { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> CoverLetterChanged { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private async Task NotifyChanged()
    {
        if (CoverLetter.Length > MaxCharacters)
        {
            CoverLetter = CoverLetter[..MaxCharacters];
        }
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }
}

@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">Review &amp; Submit</h4>

@if (!string.IsNullOrEmpty(SubmitError))
{
    <div class="alert alert-danger">@SubmitError</div>
}

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@Personal.FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Personal.Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Personal.Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Personal.Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-3 border-bottom last-no-border">
                <h6>@entry.Title at @entry.Company</h6>
                <div class="text-muted small">
                    @entry.StartDate?.ToString("MMM yyyy")
                    &ndash;
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </div>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mt-1 mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> — @r.Relationship<br />
                <span class="text-muted">@r.Email @(!string.IsNullOrWhiteSpace(r.Phone) ? $"| {r.Phone}" : "")</span>
            </div>
        }
    </div>
</div>

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(4)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;" class="mb-0">@CoverLetter</p>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-2" role="status"></span>
            <span>Submitting...</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Personal { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<WorkEntryModel> WorkEntries { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter, EditorRequired]
