@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private List<string> Errors { get; set; } = new();
    private bool IsValidatingEmail { get; set; }

    private async Task HandleNext()
    {
        Errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName))
            Errors.Add("Full name is required.");
        if (string.IsNullOrWhiteSpace(Model.Email))
            Errors.Add("Email is required.");
        if (string.IsNullOrWhiteSpace(Model.Phone))
            Errors.Add("Phone is required.");
        if (string.IsNullOrWhiteSpace(Model.Address))
            Errors.Add("Address is required.");

        if (Errors.Count > 0) return;

        IsValidatingEmail = true;
        StateHasChanged();

        var isValidEmail = await ValidateEmail(Model.Email);
        IsValidatingEmail = false;

        if (!isValidEmail)
        {
            Errors.Add("Please enter a valid email address.");
            return;
        }

        await OnNext.InvokeAsync();
    }
}

