    private List<string> Errors { get; set; } = new();

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var entry = Entries[i];
            if (string.IsNullOrWhiteSpace(entry.Company))
                Errors.Add($"Position {i + 1}: Company is required.");
            if (string.IsNullOrWhiteSpace(entry.Title))
                Errors.Add($"Position {i + 1}: Job title is required.");
            if (entry.StartDate is null)
                Errors.Add($"Position {i + 1}: Start date is required.");
        }

        if (Errors.Count > 0) return;

        await OnNext.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-adebc468969c496589f5fe7a6330b0f0/Components/Pages/Apply/ReferencesStep.razor", "file_text": "@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">References</h4>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceEditor Model="References[index]"
                     Index="index + 1"
                     CanRemove="References.Count > 2"
                     OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
</div>

@code {
    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private List<string> Errors { get; set; } = new();

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            if (string.IsNullOrWhiteSpace(r.Name))
                Errors.Add($"Reference {i + 1}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship))
                Errors.Add($"Reference {i + 1}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email))
                Errors.Add($"Reference {i + 1}: Email is required.");
        }

        if (Errors.Count > 0) return;

        await OnNext.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-adebc468969c496589f5fe7a6330b0f0/Components/Pages/Apply/CoverLetterStep.razor", "file_text": "@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="CoverLetter" @bind:event="oninput"
              @bind:after="NotifyChanged"
              placeholder="Write your cover letter here..."></textarea>
    <div class="form-text text-end">
        @CoverLetter.Length / @MaxCharacters characters
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next &raquo;</button>
</div>

@code {
    private const int MaxCharacters = 2000;

    [Parameter, EditorRequired]
    public string CoverLetter { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> CoverLetterChanged { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private async Task NotifyChanged()
    {
        if (CoverLetter.Length > MaxCharacters)
        {
            CoverLetter = CoverLetter[..MaxCharacters];
        }
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }
}
"}

{"path": "/tmp/sv-adebc468969c496589f5fe7a6330b0f0/Components/Pages/Apply/ReviewStep.razor", "file_text": "@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">Review &amp; Submit</h4>

@if (!string.IsNullOrEmpty(SubmitError))
{
    <div class="alert alert-danger">@SubmitError</div>
}

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@Personal.FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Personal.Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Personal.Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Personal.Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-3 border-bottom last-no-border">
                <h6>@entry.Title at @entry.Company</h6>
                <div class="text-muted small">
                    @entry.StartDate?.ToString("MMM yyyy")
                    &ndash;
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </div>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mt-1 mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> — @r.Relationship<br />
                <span class="text-muted">@r.Email @(!string.IsNullOrWhiteSpace(r.Phone) ? $"| {r.Phone}" : "")</span>
            </div>
        }
    </div>
</div>

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(4)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;" class="mb-0">@CoverLetter</p>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-2" role="status"></span>
            <span>Submitting...</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Personal { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<WorkEntryModel> WorkEntries { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter, EditorRequired]
    public string CoverLetter { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<int> OnEditSection { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnSubmit { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    [Parameter]
    public bool IsSubmitting { get; set; }

    [Parameter]
    public string? SubmitError { get; set; }
}
"}

