@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<nav class="step-indicator mb-4" aria-label="Application progress">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i + 1;
        var isCompleted = CompletedSteps.Contains(step);
        var isCurrent = step == CurrentStep;

        @if (i > 0)
        {
            <div class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")"></div>
        }

        <div class="step @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(step > CurrentStep && !isCompleted ? "future" : "")"
             role="listitem"
             @onclick="() => HandleStepClick(step)"
             @onclick:preventDefault>
            <div class="step-circle">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <div class="step-label">@StepNames[i]</div>
        </div>
    }
</nav>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = new();

    [Parameter, EditorRequired]
    public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

