@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryEditor Model="Entries[index]"
                     Index="index + 1"
                     CanRemove="Entries.Count > 1"
                     OnRemove="() => RemoveEntry(index)" />
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
</div>

@code {
    [Parameter, EditorRequired]
    public List<WorkEntryModel> Entries { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private List<string> Errors { get; set; } = new();

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var entry = Entries[i];
            if (string.IsNullOrWhiteSpace(entry.Company))
                Errors.Add($"Position {i + 1}: Company is required.");
            if (string.IsNullOrWhiteSpace(entry.Title))
                Errors.Add($"Position {i + 1}: Job title is required.");
            if (entry.StartDate is null)
                Errors.Add($"Position {i + 1}: Start date is required.");
        }

        if (Errors.Count > 0) return;

        await OnNext.InvokeAsync();
    }
}

