+            if (string.IsNullOrWhiteSpace(r.Email))
+                Errors.Add($"Reference {i + 1}: Email is required.");
+        }
+
+        if (Errors.Count > 0) return;
+
+        await OnNext.InvokeAsync();
+    }
+}
