@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="CoverLetter" @bind:event="oninput"
              @bind:after="NotifyChanged"
              placeholder="Write your cover letter here..."></textarea>
    <div class="form-text text-end">
        @CoverLetter.Length / @MaxCharacters characters
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next &raquo;</button>
</div>

@code {
    private const int MaxCharacters = 2000;

    [Parameter, EditorRequired]
    public string CoverLetter { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> CoverLetterChanged { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private async Task NotifyChanged()
    {
        if (CoverLetter.Length > MaxCharacters)
        {
            CoverLetter = CoverLetter[..MaxCharacters];
        }
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }
}

@namespace sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply

<h4 class="mb-3">Review &amp; Submit</h4>

@if (!string.IsNullOrEmpty(SubmitError))
{
    <div class="alert alert-danger">@SubmitError</div>
}

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@Personal.FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Personal.Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Personal.Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Personal.Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-3 border-bottom last-no-border">
                <h6>@entry.Title at @entry.Company</h6>
                <div class="text-muted small">
                    @entry.StartDate?.ToString("MMM yyyy")
                    &ndash;
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </div>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mt-1 mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> — @r.Relationship<br />
                <span class="text-muted">@r.Email @(!string.IsNullOrWhiteSpace(r.Phone) ? $"| {r.Phone}" : "")</span>
            </div>
        }
    </div>
</div>

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(4)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;" class="mb-0">@CoverLetter</p>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-2" role="status"></span>
            <span>Submitting...</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Personal { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<WorkEntryModel> WorkEntries { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter, EditorRequired]
    public string CoverLetter { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<int> OnEditSection { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnSubmit { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    [Parameter]
    public bool IsSubmitting { get; set; }

    [Parameter]
    public string? SubmitError { get; set; }
}

