@page "/apply"
@rendermode InteractiveServer
@using sv_adebc468969c496589f5fe7a6330b0f0.Models
@using sv_adebc468969c496589f5fe7a6330b0f0.Components.Pages.Apply
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    @if (submittedId.HasValue)
    {
        <div class="text-center py-5">
            <div class="mb-3">
                <span style="font-size: 3rem; color: green;">&#10003;</span>
            </div>
            <h3>Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@submittedId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep"
                       CompletedSteps="completedSteps"
                       OnStepClicked="GoToStep" />

        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="personalInfo"
                                  OnNext="() => AdvanceStep(2)"
                                  ValidateEmail="ApplicationService.ValidateEmailAsync" />
                break;
            case 2:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="() => AdvanceStep(3)"
                                 OnBack="() => GoToStep(1)" />
                break;
            case 3:
                <ReferencesStep References="references"
                                OnNext="() => AdvanceStep(4)"
                                OnBack="() => GoToStep(2)" />
                break;
            case 4:
                <CoverLetterStep CoverLetter="@coverLetter"
                                 CoverLetterChanged="val => coverLetter = val"
                                 OnNext="() => AdvanceStep(5)"
                                 OnBack="() => GoToStep(3)" />
                break;
            case 5:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="@coverLetter"
                            OnEditSection="GoToStep"
                            OnSubmit="SubmitApplication"
                            OnBack="() => GoToStep(4)"
                            IsSubmitting="isSubmitting"
                            SubmitError="@submitError" />
                break;
        }
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new() };
    private List<ReferenceModel> references = new() { new(), new() };
    private string coverLetter = "";

    private bool isSubmitting;
    private string? submitError;
    private int? submittedId;

    private void AdvanceStep(int nextStep)
    {
        completedSteps.Add(currentStep);
        currentStep = nextStep;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task SubmitApplication()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            var application = new JobApplication(
                new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
                new WorkHistory(workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate!.Value,
                    e.IsCurrent ? null : e.EndDate, e.Description)).ToList()),
                references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                coverLetter
            );

            submittedId = await ApplicationService.SubmitApplicationAsync(application);
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

::deep .step-indicator {
    display: flex;
    align-items: flex-start;
    justify-content: center;
    gap: 0;
    flex-wrap: wrap;
}

::deep .step {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    opacity: 0.4;
    transition: opacity 0.2s;
    min-width: 100px;
}

::deep .step.current {
    opacity: 1;
}

::deep .step.completed {
    opacity: 1;
    cursor: pointer;
}

::deep .step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

::deep .step.current .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

::deep .step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

::deep .step-label {
    margin-top: 0.4rem;
    font-size: 0.75rem;
    text-align: center;
    color: #6c757d;
    white-space: nowrap;
}

::deep .step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

::deep .step.completed .step-label {
    color: #198754;
}

::deep .step-connector {
    height: 2px;
    flex: 1;
    min-width: 30px;
    max-width: 60px;
    background: #dee2e6;
    margin-top: 18px;
    transition: background 0.2s;
}

::deep .step-connector.completed {
    background: #198754;
}

