toolArgs.file_text:
::deep .step-indicator {
    display: flex;
    align-items: flex-start;
    justify-content: center;
    gap: 0;
    flex-wrap: wrap;
}

::deep .step {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    opacity: 0.4;
    transition: opacity 0.2s;
    min-width: 100px;
}

::deep .step.current {
    opacity: 1;
}

::deep .step.completed {
    opacity: 1;
    cursor: pointer;
}

::deep .step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

::deep .step.current .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

::deep .step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

::deep .step-label {
    margin-top: 0.4rem;
    font-size: 0.75rem;
    text-align: center;
    color: #6c757d;
    white-space: nowrap;
}

::deep .step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

::deep .step.completed .step-label {
    color: #198754;
}

::deep .step-connector {
    height: 2px;
    flex: 1;
    min-width: 30px;
    max-width: 60px;
    background: #dee2e6;
    margin-top: 18px;
    transition: background 0.2s;
}

::deep .step-connector.completed {
    background: #198754;
}

